import 'package:jaspr/jaspr.dart';
import 'package:jaspr/dom.dart';

class SocialIcons extends StatelessComponent {
  const SocialIcons({this.socials = const {}, super.key});

  /// Map of platform name → URL, sourced from `content/_data/site.yaml`.
  /// Missing platforms render with `'#'` as the href.
  final Map<String, String> socials;

  String _url(String platform) => socials[platform] ?? '#';

  Component _icon(String label, String href, String svg) {
    // Open external links in a new tab; mailto: and placeholder '#' open in
    // place because new-tab on those is either pointless or annoying.
    final external = href.isNotEmpty && href != '#' && !href.startsWith('mailto:');
    final attrs = <String, String>{'title': label, 'aria-label': label, 'rel': 'me'};
    if (external) {
      attrs['target'] = '_blank';
      attrs['rel'] = 'me noopener noreferrer';
    }
    return a(href: href, classes: 'social', attributes: attrs, [raw(svg)]);
  }

  @override
  Component build(BuildContext context) {
    return div(classes: 'socials', [
      _icon('LinkedIn', _url('linkedin'), _linkedIn),
      _icon('ORCID', _url('orcid'), _orcid),
      _icon('Google Scholar', _url('scholar'), _scholar),
      _icon('ResearchGate', _url('researchgate'), _researchGate),
      _icon('GitHub', _url('github'), _github),
      span(classes: 'socials__sep', []),
      _icon('YouTube', _url('youtube'), _youtube),
      _icon('X (Twitter)', _url('x'), _x),
      _icon('Instagram', _url('instagram'), _instagram),
      _icon('Snapchat', _url('snapchat'), _snapchat),
      span(classes: 'socials__sep', []),
      _icon('Email', _url('email'), _email),
    ]);
  }
}

